const response = $input.first().json;

if (response.status !== "success") {
  throw new Error(`CricAPI error: ${response.status}`);
}

const matches = response.data || [];

// Find live IPL match dynamically
const iplMatch = matches.find(m => {
  const name = (m.name || '').toUpperCase();
  const isIPL = name.includes('IPL') || name.includes('INDIAN PREMIER LEAGUE');
  const isT20 = (m.matchType || '').toLowerCase() === 't20';
  const isLive = m.matchStarted === true && m.matchEnded === false;
  return isIPL && isT20 && isLive;
});

// Fallback to any live T20 for testing when IPL is not on
const match = iplMatch || matches.find(m =>
  (m.matchType || '').toLowerCase() === 't20' &&
  m.matchStarted === true &&
  m.matchEnded === false &&
  m.score && m.score.length > 0
);

// Further fallback — use any T20 with scores for demo purposes
const demoMatch = match || matches.find(m =>
  (m.matchType || '').toLowerCase() === 't20' &&
  m.score && m.score.length > 0
);

if (!demoMatch) {
  return [{ json: { skip: true, reason: 'No T20 matches available' } }];
}

const isLiveIPL = !!iplMatch;
const scores = demoMatch.score || [];
const innings = scores.length >= 2 ? '2nd' : '1st';

let narrative_data = {};

if (innings === '1st') {
  const batting = scores[0] || {};
  const runs = batting.r || 0;
  const wickets = batting.w || 0;
  const overs = parseFloat(batting.o) || 0;
  const oversRemaining = Math.max(0, 20 - overs);
  const crr = overs > 0 ? (runs / overs).toFixed(2) : '0.00';
  const projectedTotal = Math.round(runs + (parseFloat(crr) * oversRemaining));

  let phase = 'Middle overs';
  if (overs <= 6) phase = 'Powerplay';
  else if (overs >= 15) phase = 'Death overs';

  let pressure = 'Medium';
  if (wickets >= 6) pressure = 'High';
  else if (wickets <= 2 && overs <= 10) pressure = 'Low';

  narrative_data = {
    innings: '1st',
    battingTeam: demoMatch.teams?.[0] || 'Team A',
    bowlingTeam: demoMatch.teams?.[1] || 'Team B',
    score: `${runs}/${wickets}`,
    overs,
    oversRemaining: oversRemaining.toFixed(1),
    crr,
    projectedTotal,
    wicketsInHand: 10 - wickets,
    phase,
    pressure,
    target: null,
    rrr: null,
    runsNeeded: null
  };

} else {
  const firstInnings = scores[0] || {};
  const secondInnings = scores[1] || {};
  const target = (firstInnings.r || 0) + 1;
  const runs = secondInnings.r || 0;
  const wickets = secondInnings.w || 0;
  const overs = parseFloat(secondInnings.o) || 0;
  const oversRemaining = Math.max(0, 20 - overs);
  const runsNeeded = target - runs;
  const crr = overs > 0 ? (runs / overs).toFixed(2) : '0.00';
  const rrr = oversRemaining > 0 ? (runsNeeded / oversRemaining).toFixed(2) : '99.00';
  const rrrGap = (parseFloat(rrr) - parseFloat(crr)).toFixed(2);

  let phase = 'Middle overs';
  if (overs <= 6) phase = 'Powerplay';
  else if (overs >= 15) phase = 'Death overs';

  let pressure = 'Medium';
  if (parseFloat(rrr) > 12 || wickets >= 7) pressure = 'High';
  else if (parseFloat(rrr) < 8 && wickets <= 4) pressure = 'Low';

  narrative_data = {
    innings: '2nd',
    battingTeam: demoMatch.teams?.[1] || 'Team B',
    bowlingTeam: demoMatch.teams?.[0] || 'Team A',
    score: `${runs}/${wickets}`,
    overs,
    oversRemaining: oversRemaining.toFixed(1),
    target,
    runsNeeded,
    crr,
    rrr,
    rrrGap,
    wicketsInHand: 10 - wickets,
    phase,
    pressure,
    projectedTotal: null
  };
}

// Build OpenAI prompt based on innings
let prompt = '';

if (narrative_data.innings === '1st') {
  prompt = `You are an IPL cricket commentator writing a punchy 2-sentence win-probability narrative for a fan app.

Match: ${narrative_data.battingTeam} vs ${narrative_data.bowlingTeam}
Innings: 1st innings
Phase: ${narrative_data.phase}
Score: ${narrative_data.score} in ${narrative_data.overs} overs
Current Run Rate: ${narrative_data.crr}
Wickets in Hand: ${narrative_data.wicketsInHand}
Overs Remaining: ${narrative_data.oversRemaining}
Projected Total: ${narrative_data.projectedTotal}
Pressure Level: ${narrative_data.pressure}

Write exactly 2 sentences. Be specific about the numbers provided. Sound like a human analyst not a robot. Use cricket language fans understand. No percentages allowed.`;

} else {
  prompt = `You are an IPL cricket commentator writing a punchy 2-sentence win-probability narrative for a fan app.

Match: ${narrative_data.battingTeam} chasing ${narrative_data.target} vs ${narrative_data.bowlingTeam}
Innings: 2nd innings (chase)
Phase: ${narrative_data.phase}
Score: ${narrative_data.score} in ${narrative_data.overs} overs
Runs Needed: ${narrative_data.runsNeeded} off ${narrative_data.oversRemaining} overs
Required Run Rate: ${narrative_data.rrr}
Current Run Rate: ${narrative_data.crr}
Run Rate Gap: ${narrative_data.rrrGap}
Wickets in Hand: ${narrative_data.wicketsInHand}
Pressure Level: ${narrative_data.pressure}

Write exactly 2 sentences. Be specific about the numbers provided. Sound like a human analyst not a robot. Use cricket language fans understand. No percentages allowed.`;
}

return [{
  json: {
    ...narrative_data,
    matchName: demoMatch.name,
    isLiveIPL,
    prompt,
    timestamp: new Date().toISOString()
  }
}];

const response = $input.first().json;

// Correct path for n8n OpenAI node output
const narrative = response.output?.[0]?.content?.[0]?.text || 'Narrative unavailable.';

const data = $('Compute Match Indicators').first().json;

return [{
  json: {
    ...data,
    narrative
  }
}];
